parameters.jsCode:
const item = $input.first();
const body = (item.json && item.json.body) || item.json || {};

const candidateName = (body.candidateName || '').toString().trim();
const candidateEmail = (body.candidateEmail || '').toString().trim();
const jobTitle = (body.jobTitle || '').toString().trim();
const jobDescription = (body.jobDescription || '').toString().trim();
const score = body.score;
const classification = (body.classification || '').toString().trim();
const summary = (body.summary || '').toString().trim();
const strengths = (body.strengths || '').toString().trim();
const gaps = (body.gaps || '').toString().trim();
const recommendation = (body.recommendation || '').toString().trim();
const currentSubject = (body.currentSubject || '').toString();
const currentBody = (body.currentBody || '').toString();
const userMessage = (body.userMessage || '').toString().trim();

let chatHistory = [];
try {
  const parsed = JSON.parse(body.chatHistory || '[]');
  if (Array.isArray(parsed)) chatHistory = parsed;
} catch (e) {
  chatHistory = [];
}

const errors = [];
if (!candidateEmail) errors.push('Missing candidateEmail');
if (!userMessage) errors.push('Missing userMessage');

return [{
  json: {
    isValid: errors.length === 0,
    validationError: errors.join('; '),
    candidateName,
    candidateEmail,
    jobTitle,
    jobDescription,
    score,
    classification,
    summary,
    strengths,
    gaps,
    recommendation,
    currentSubject,
    currentBody,
    userMessage,
    chatHistory
  }
}];

const item = $input.first().json;

const historyText = (item.chatHistory || [])
  .map((m) => `${m.role === 'user' ? 'HR' : 'Assistant'}: ${(m.text || '').toString()}`)
  .join('\n');

const prompt = `CANDIDATE REPORT
Name: ${item.candidateName || 'Unknown'}
Email: ${item.candidateEmail}
Overall Score: ${item.score != null ? item.score : 'N/A'}/100
Fit: ${item.classification || 'Not specified'}
Summary: ${item.summary || 'Not specified'}
Strengths: ${item.strengths || 'Not specified'}
Gaps: ${item.gaps || 'Not specified'}
Recommendation: ${item.recommendation || 'Not specified'}

JOB CONTEXT
Title: ${item.jobTitle || 'Not specified'}
Description: ${item.jobDescription || 'Not specified'}

CURRENT DRAFT
Subject: ${item.currentSubject || '(empty)'}
Body: ${item.currentBody || '(empty)'}

CONVERSATION SO FAR
${historyText || '(none yet)'}

LATEST HR INSTRUCTION
${item.userMessage}`;

return [{
  json: {
    candidateEmail: item.candidateEmail,
    prompt
  }
}];

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "subject": { "type": "string", "description": "Email subject line" },
    "body": { "type": "string", "description": "Full email body text, professional tone, ready to send as-is" },
    "assistantReply": { "type": "string", "description": "1-2 sentence note to show HR in the chat, describing what was written or changed" }
  },
  "required": ["subject", "body", "assistantReply"]
}
